import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to begin inspecting a target user.
 * Mirrors the server-side StartInspectEvent packet structure.
 */
export class StartInspectComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(targetId: number) {
        this._data = [targetId];
        console.log(
            `[📤] StartInspectComposer → Watching targetId=${targetId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
